const input = $input.first().json;
const filters = {
  hostname: input.hostname || null,
  filter_by_type: input.filter_by_type || null,
  filter_by_ids: input.filter_by_ids ? JSON.parse(input.filter_by_ids) : null
};
console.log('NetBox-Abfrage: Input Parameters =', JSON.stringify(filters));
if (filters.hostname) {
  console.log(`🎯 Suche nach Hostname: "${filters.hostname}"`);
} else if (filters.filter_by_type) {
  console.log(`🎯 Suche nach Type: "${filters.filter_by_type}"`);
} else if (filters.filter_by_ids) {
  console.log(`🎯 Suche nach IDs: ${JSON.stringify(filters.filter_by_ids)}`);
} else {
  console.log(`📋 Keine Filter - alle Objekte werden zurückgegeben`);
}
return { json: filters };

const items = $input.all();
const params = $('🔧 Parse Input Parameters').first().json;
const hostname = (params.hostname || '').trim().toLowerCase();
const filterByType = (params.filter_by_type || '').trim().toLowerCase();
const filterByIds = Array.isArray(params.filter_by_ids) ? params.filter_by_ids : [];

console.log(`\n📥 PARSER: ${items.length} Rohobjekte von NetBox`);
console.log(`🔧 Filter: hostname="${hostname}", type="${filterByType}", ids=${JSON.stringify(filterByIds)}`);

// Step 1: Extrahiere Hostname, IP, SSH-Daten
let processed = items.map(item => {
  const obj = item.json;
  const objHostname = (obj.name || '').trim().toLowerCase();

  // IP extrahieren
  let ip = null;
  if (obj.primary_ip4 && obj.primary_ip4.address) {
    ip = obj.primary_ip4.address.split('/')[0];
  } else if (obj.primary_ip && obj.primary_ip.address) {
    ip = obj.primary_ip.address.split('/')[0];
  }

  // Objekte OHNE IP filtern
  if (!ip) {
    console.log(`  ⏭️ "${obj.name}" hat keine IP - übersprungen`);
    return null;
  }

  // SSH-Daten
  const cf = obj.custom_fields || {};
  const default_user = obj.type === 'device' ? 'admin' : 'root';
  const ssh_user = cf.ssh_username || default_user;
  const ssh_password = cf.ssh_password || null;

  return {
    json: {
      id: obj.id,
      type: (obj.type || 'unknown').trim().toLowerCase(),
      hostname_raw: obj.name,
      hostname: objHostname,
      ip: ip,
      ssh_user: ssh_user,
      ssh_password: ssh_password
    }
  };
}).filter(item => item !== null);

console.log(`✅ Nach IP-Filter: ${processed.length} Objekte mit IP`);

// Step 2: Wende Filterung an
let filtered = processed;

// PRIORITÄT 1: Hostname-Filter (exakt und streng!)
if (hostname && hostname.length > 0) {
  const beforeFilter = filtered.length;
  filtered = filtered.filter(item => {
    const match = item.json.hostname === hostname;
    if (!match) {
      console.log(`  🔍 "${item.json.hostname_raw}" != "${hostname}" (Hostname-Filter)`);
    }
    return match;
  });
  console.log(`🎯 HOSTNAME FILTER: ${beforeFilter} → ${filtered.length} Objekt(e)`);

  // WICHTIG: Wenn Hostname gegeben, STOP hier! Keine anderen Filter!
} else {
  // PRIORITÄT 2: Type-Filter (nur wenn KEIN Hostname)
  if (filterByType && filterByType.length > 0) {
    const beforeFilter = filtered.length;
    filtered = filtered.filter(item => item.json.type === filterByType);
    console.log(`🎯 TYPE FILTER "${filterByType}": ${beforeFilter} → ${filtered.length} Objekt(e)`);
  }

  // PRIORITÄT 3: ID-Filter (nur wenn KEIN Hostname)
  if (filterByIds && filterByIds.length > 0) {
    const beforeFilter = filtered.length;
    filtered = filtered.filter(item => filterByIds.includes(item.json.id));
    console.log(`🎯 ID FILTER: ${beforeFilter} → ${filtered.length} Objekt(e)`);
  }
}

// Step 3: Formatiere Output (nur 4 Felder)
const output = filtered.map(item => ({
  json: {
    hostname: item.json.hostname_raw,
    ip: item.json.ip,
    ssh_user: item.json.ssh_user,
    ssh_password: item.json.ssh_password
  }
}));

console.log(`\n✅ FINAL OUTPUT: ${output.length} Objekt(e) zurückgegeben\n`);
return output;
